import{_ as t,o as a,c as l,a5 as o}from"./chunks/framework.B5tqjWbr.js";const h=JSON.parse('{"title":"教程 0028：保护去抖与故障锁存","description":"","frontmatter":{"title":"教程 0028：保护去抖与故障锁存","date":"2026-07-02T00:00:00.000Z","section":"电源控制","chapter":"01-Lessons","chapterTitle":"电源课程","category":"电源控制","tags":["imported"],"source":"power","sourcePath":"0028-ups-fault-latch-debounce.html","status":"learning","visibility":"public","summary":"Imported from 0028-ups-fault-latch-debounce.html","chapterOrder":10},"headers":[],"relativePath":"content/power/lessons/0028-ups-fault-latch-debounce.md","filePath":"content/power/lessons/0028-ups-fault-latch-debounce.md","lastUpdated":null}'),p={name:"content/power/lessons/0028-ups-fault-latch-debounce.md"};function i(c,e,u,n,s,r){return a(),l("div",null,[...e[0]||(e[0]=[o(`<h1 id="教程-0028-保护去抖与故障锁存" tabindex="-1">教程 0028：保护去抖与故障锁存 <a class="header-anchor" href="#教程-0028-保护去抖与故障锁存" aria-label="Permalink to &quot;教程 0028：保护去抖与故障锁存&quot;">​</a></h1><p>中文主讲。一个概念：瞬时保护标志不能直接等于最终故障状态，必须经过确认、锁存和安全复位。</p><pre><code>目录
</code></pre><ul><li><p>它是什么</p></li><li><p>为什么 UPS 需要它</p></li><li><p>物理直觉</p></li><li><p>数学形式</p></li><li><p>一个仿真任务与仿真观察</p></li><li><p>固件落地</p></li><li><p>常见误解</p></li><li><p>验收标准、复盘问题、导师问题</p></li></ul><p>**保密边界：**本节只使用教学故障序列和教学确认次数，不包含公司内部故障策略、未公开产品方案、客户项目参数或内部测试数据。</p><h2 id="_1-它是什么" tabindex="-1">1. 它是什么 <a class="header-anchor" href="#_1-它是什么" aria-label="Permalink to &quot;1. 它是什么&quot;">​</a></h2><p>保护去抖（protection debounce）是要求保护标志连续满足若干次后才确认故障。故障锁存（fault latch）是故障一旦确认，即使瞬时输入恢复正常，也保持故障状态，直到复位请求（reset request）和安全复位条件（safe-to-reset condition）同时满足。</p><p>本节只讲一个概念：瞬时保护标志不能直接等于最终故障状态。</p><h2 id="_2-为什么-ups-需要它" tabindex="-1">2. 为什么 UPS 需要它 <a class="header-anchor" href="#_2-为什么-ups-需要它" aria-label="Permalink to &quot;2. 为什么 UPS 需要它&quot;">​</a></h2><p>UPS 的采样值会有噪声、纹波和瞬态扰动。如果一个采样点越界就立刻锁死，系统会被短毛刺频繁打断。但如果故障确认后不锁存，严重故障又可能因为输入短暂恢复而被自动清掉。</p><p>去抖解决“短毛刺误触发”，锁存解决“严重故障必须保持并等待人工或系统复位”。</p><h2 id="_3-物理直觉" tabindex="-1">3. 物理直觉 <a class="header-anchor" href="#_3-物理直觉" aria-label="Permalink to &quot;3. 物理直觉&quot;">​</a></h2><p>保护标志像报警铃声，去抖像“连续听到几声才确认不是误响”，故障锁存像“确认火警后不能因为铃声停了一下就自动解除警报”。</p><h2 id="_4-数学形式" tabindex="-1">4. 数学形式 <a class="header-anchor" href="#_4-数学形式" aria-label="Permalink to &quot;4. 数学形式&quot;">​</a></h2><p>if reset_request AND safe_to_reset: consecutive_fault_count = 0 latched_fault = 0 else if fault_input: consecutive_fault_count += 1 if consecutive_fault_count &gt;= fault_confirm_count: latched_fault = 1 else: consecutive_fault_count = 0</p><p><code>fault_confirm_count</code> 是教学确认次数，不代表真实产品参数。这个逻辑可以放在控制中断服务程序（control interrupt service routine / control ISR）周期里，也可以放在固定周期保护任务里。</p><h2 id="_5-一个仿真任务与仿真观察" tabindex="-1">5. 一个仿真任务与仿真观察 <a class="header-anchor" href="#_5-一个仿真任务与仿真观察" aria-label="Permalink to &quot;5. 一个仿真任务与仿真观察&quot;">​</a></h2><p>运行 Python 仿真：</p><p>cd E:\\gitee_CodeStorage\\学习\\电源 python simulations\\python\\ups_fault_latch_debounce.py</p><p>只保存图片、不自动打开：</p><p>python simulations\\python\\ups_fault_latch_debounce.py --no-open</p><pre><code>产物
</code></pre><ul><li><p><code>simulations/results/ups_fault_latch_debounce.png</code></p></li><li><p>终端输出：短毛刺是否锁存、连续故障是否锁存、复位是否清除锁存。</p></li><li><p>图内包含参数框、图例、确认次数阈值和复位条件。</p></li></ul><p>观察顺序：先看短毛刺只持续 1 个采样点，连续计数没到确认次数；再看连续故障让计数达到阈值并锁存；最后看复位请求和安全复位条件同时为 1 后锁存清除。</p><h2 id="_6-固件落地" tabindex="-1">6. 固件落地 <a class="header-anchor" href="#_6-固件落地" aria-label="Permalink to &quot;6. 固件落地&quot;">​</a></h2><ul><li><p><code>UpsFaultLatch</code>：保存连续故障计数和锁存状态。</p></li><li><p><code>UpsFaultLatch_Step()</code>：每个 ISR 周期或保护任务周期调用一次。</p></li><li><p><code>fault_input</code>：来自上一节 <code>UpsProtection_Evaluate()</code> 的瞬时保护标志。</p></li><li><p><code>reset_request &amp;&amp; safe_to_reset</code>：复位必须同时有请求和安全条件。</p></li></ul><h2 id="_7-常见误解" tabindex="-1">7. 常见误解 <a class="header-anchor" href="#_7-常见误解" aria-label="Permalink to &quot;7. 常见误解&quot;">​</a></h2><ul><li><p>**误解：**去抖会让保护变慢，所以不该用。 **纠正：**关键保护要权衡响应速度和误触发，确认次数必须按风险分级。</p></li><li><p>**误解：**故障输入恢复正常就应该自动清锁存。 **纠正：**严重故障通常需要复位请求、安全条件和记录闭环。</p></li><li><p>**误解：**所有保护都用同一个确认次数。 **纠正：**过流、过压、温度、旁路同步等保护的时间尺度不同。</p></li></ul><h2 id="_8-验收标准" tabindex="-1">8. 验收标准 <a class="header-anchor" href="#_8-验收标准" aria-label="Permalink to &quot;8. 验收标准&quot;">​</a></h2><ul><li><p>能运行 <code>python simulations\\python\\ups_fault_latch_debounce.py --no-open</code> 并打开 <code>simulations/results/ups_fault_latch_debounce.png</code>。</p></li><li><p>能解释短毛刺为什么没有锁存。</p></li><li><p>能解释连续故障为什么锁存。</p></li><li><p>能解释为什么复位需要 <code>reset_request &amp;&amp; safe_to_reset</code>。</p></li><li><p>能基于 <code>fault_latch.c -&gt; UpsFaultLatch_Step()</code> 准备导师问题。</p></li></ul><h2 id="_9-复盘问题" tabindex="-1">9. 复盘问题 <a class="header-anchor" href="#_9-复盘问题" aria-label="Permalink to &quot;9. 复盘问题&quot;">​</a></h2><ul><li><p>为什么短毛刺不应该直接触发故障锁存？</p></li><li><p>为什么连续故障确认后，即使输入恢复，也不能自动清锁存？</p></li><li><p>如果过流保护和温度保护都用同一个确认次数，会有什么风险？</p></li></ul><h2 id="_10-导师问题" tabindex="-1">10. 导师问题 <a class="header-anchor" href="#_10-导师问题" aria-label="Permalink to &quot;10. 导师问题&quot;">​</a></h2><ul><li><p>我用 <code>fault_latch.c -&gt; UpsFaultLatch_Step()</code> 看到故障确认次数和锁存分开实现。真实工程里不同保护会不会有不同确认时间？</p></li><li><p>我用 <code>simulations/results/ups_fault_latch_debounce.png</code> 看到短毛刺没有锁存。真实工程里哪些保护允许去抖，哪些保护必须快速关断？</p></li><li><p>我不会记录公司内部故障策略，只想确认组织方式：真实工程里复位请求和安全复位条件通常在哪个模块统一判断？</p></li></ul><p>**下一步：**可以把故障锁存结果接回 UPS 模式状态机，让故障状态、输出许可和复位流程形成完整闭环。</p><p>关联：<a href="./0027-ups-c-protection-flags.html">上一节：UPS 保护标志</a>；源稿：<code>concepts/embedded/ups-fault-latch-debounce.md</code>；仿真：<code>simulations/python/ups_fault_latch_debounce.py</code>。</p><pre><code>上一节：教程 0027：UPS 保护标志
下一节：教程 0029：系统故障闭环
</code></pre>`,37)])])}const _=t(p,[["render",i]]);export{h as __pageData,_ as default};
